namespace sv_0a41efdbc00f4e2ab90cc797d849a62a.Models;

// Service contract records
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class ApplicationFormModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";
    public List<WorkEntryModel> WorkEntries { get; set; } = [new()];
    public List<ReferenceModel> References { get; set; } = [new(), new()];
    public string CoverLetter { get; set; } = "";

    public JobApplication ToRecord() => new(
        new PersonalInfo(FullName, Email, Phone, Address),
        new WorkHistory(WorkEntries.Select(w => new WorkEntry(
            w.Company, w.Title,
            w.StartDate ?? DateTime.Today,
            w.IsCurrent ? null : w.EndDate,
            w.Description)).ToList()),
        References.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
        CoverLetter);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
}

@namespace sv_0a41efdbc00f4e2ab90cc797d849a62a.Components.Pages.Apply

<nav aria-label="Application steps" class="step-indicator mb-4">
    <ol class="d-flex list-unstyled justify-content-between mb-0 p-0">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isCurrent = step == CurrentStep;
            var isCompleted = CompletedSteps.Contains(step);
            var isFuture = !isCurrent && !isCompleted;

            <li class="step-item flex-fill text-center @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")">
                @if (isCompleted)
                {
                    <button class="btn btn-link text-decoration-none p-0 w-100" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="step-circle bg-success text-white">&#10003;</span>
                        <span class="step-label d-block small text-success fw-semibold">@StepNames[i]</span>
                    </button>
                }
                else
                {
                    <div class="p-0 w-100">
                        <span class="step-circle @(isCurrent ? "bg-primary text-white" : "bg-secondary text-white opacity-50")">@step</span>
                        <span class="step-label d-block small @(isCurrent ? "text-primary fw-semibold" : "text-muted")">@StepNames[i]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

@namespace sv_0a41efdbc00f4e2ab90cc797d849a62a.Components.Pages.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @Index</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Reference.Name" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Reference.Relationship" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="Reference.Email" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="Reference.Phone" @bind:event="oninput" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter, EditorRequired] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

