@namespace sv_0a41efdbc00f4e2ab90cc797d849a62a.Components.Pages.Apply

<nav aria-label="Application steps" class="step-indicator mb-4">
    <ol class="d-flex list-unstyled justify-content-between mb-0 p-0">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isCurrent = step == CurrentStep;
            var isCompleted = CompletedSteps.Contains(step);
            var isFuture = !isCurrent && !isCompleted;

            <li class="step-item flex-fill text-center @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")">
                @if (isCompleted)
                {
                    <button class="btn btn-link text-decoration-none p-0 w-100" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="step-circle bg-success text-white">&#10003;</span>
                        <span class="step-label d-block small text-success fw-semibold">@StepNames[i]</span>
                    </button>
                }
                else
                {
                    <div class="p-0 w-100">
                        <span class="step-circle @(isCurrent ? "bg-primary text-white" : "bg-secondary text-white opacity-50")">@step</span>
                        <span class="step-label d-block small @(isCurrent ? "text-primary fw-semibold" : "text-muted")">@StepNames[i]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

