@namespace sv_0a41efdbc00f4e2ab90cc797d849a62a.Components.Pages.Apply

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.FullName" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(emailInvalid ? "is-invalid" : "")"
               @bind="Model.Email" @bind:event="oninput" />
        @if (emailInvalid)
        {
            <div class="invalid-feedback">Please enter a valid email address.</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.Address" @bind:event="oninput" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
        @if (isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private string? ErrorMessage;
    private bool emailInvalid;
    private bool isValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;
        emailInvalid = false;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        isValidating = true;
        try
        {
            var valid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!valid)
            {
                emailInvalid = true;
                ErrorMessage = "The email address is not valid.";
                return;
            }
        }
        finally
        {
            isValidating = false;
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_0a41efdbc00f4e2ab90cc797d849a62a.Components.Pages.Apply

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

@for (int i = 0; i < Model.WorkEntries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Model.WorkEntries[index]"
                   Index="index + 1"
                   CanRemove="Model.WorkEntries.Count > 1"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-primary btn-sm mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddEntry() => Model.WorkEntries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Model.WorkEntries.Count > 1)
            Model.WorkEntries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;
        foreach (var entry in Model.WorkEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate is null)
            {
                errorMessage = "Company, job title, and start date are required for each position.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_0a41efdbc00f4e2ab90cc797d849a62a.Components.Pages.Apply

<h4 class="mb-3">References</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

@for (int i = 0; i < Model.References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="Model.References[index]"
                   Index="index + 1"
                   CanRemove="Model.References.Count > 2"
                   OnRemove="() => RemoveReference(index)" />
}

@if (Model.References.Count < 3)
{
    <button type="button" class="btn btn-outline-primary btn-sm mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddReference()
    {
        if (Model.References.Count < 3)
            Model.References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (Model.References.Count > 2)
            Model.References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;
        foreach (var r in Model.References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
            {
                errorMessage = "All fields are required for each reference.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_0a41efdbc00f4e2ab90cc797d849a62a.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="mb-3">
    <textarea class="form-control" rows="12" maxlength="@MaxLength"
              @bind="Model.CoverLetter" @bind:event="oninput"></textarea>
    <div class="form-text text-end">
        @Model.CoverLetter.Length / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private async Task HandleNext()
    {
        errorMessage = null;
        if (string.IsNullOrWhiteSpace(Model.CoverLetter))
        {
            errorMessage = "Please enter a cover letter.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_0a41efdbc00f4e2ab90cc797d849a62a.Components.Pages.Apply

<h4 class="mb-3">Review Your Application</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@if (SubmittedId.HasValue)
{
    <div class="alert alert-success text-center">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@SubmittedId</strong>. We'll be in touch!</p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Model.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Model.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Model.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Model.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in Model.WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted small">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in Model.References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@Model.CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public int? SubmittedId { get; set; }
    [Parameter] public string? ErrorMessage { get; set; }
}

