@namespace sv_0a41efdbc00f4e2ab90cc797d849a62a.Components.Pages.Apply

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

@for (int i = 0; i < Model.WorkEntries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Model.WorkEntries[index]"
                   Index="index + 1"
                   CanRemove="Model.WorkEntries.Count > 1"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-primary btn-sm mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddEntry() => Model.WorkEntries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Model.WorkEntries.Count > 1)
            Model.WorkEntries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;
        foreach (var entry in Model.WorkEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate is null)
            {
                errorMessage = "Company, job title, and start date are required for each position.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

