toolArgs.file_text:
@namespace sv_0a41efdbc00f4e2ab90cc797d849a62a.Components.Pages.Apply

<h4 class="mb-3">Review Your Application</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@if (SubmittedId.HasValue)
{
    <div class="alert alert-success text-center">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@SubmittedId</strong>. We'll be in touch!</p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Model.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Model.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Model.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Model.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in Model.WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted small">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in Model.References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@Model.CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public int? SubmittedId { get; set; }
    [Parameter] public string? ErrorMessage { get; set; }
}

arguments.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_0a41efdbc00f4e2ab90cc797d849a62a.Models
@using sv_0a41efdbc00f4e2ab90cc797d849a62a.Components.Pages.Apply
@inject IApplicationService AppService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (currentStep)
        {
            case 1:
                <PersonalInfoStep Model="model"
                                  ApplicationService="AppService"
                                  OnNext="NextStep" />
                break;
            case 2:
                <WorkHistoryStep Model="model"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 3:
                <ReferencesStep Model="model"
                                OnNext="NextStep"
                                OnBack="PreviousStep" />
                break;
            case 4:
                <CoverLetterStep Model="model"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 5:
                <ReviewStep Model="model"
                            OnBack="PreviousStep"
                            OnSubmit="HandleSubmit"
                            OnEdit="GoToStep"
                            IsSubmitting="isSubmitting"
                            SubmittedId="submittedId"
                            ErrorMessage="submitError" />
                break;
        }
    </div>
</div>

@code {
    private ApplicationFormModel model = new();
    private int currentStep = 1;
    private HashSet<int> completedSteps = [];
    private bool isSubmitting;
    private int? submittedId;
    private string? submitError;

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        if (currentStep < 5) currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 1) currentStep--;
    }

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
            currentStep = step;
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            var application = model.ToRecord();
            submittedId = await AppService.SubmitApplicationAsync(application);
            completedSteps.Add(5);
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 2rem;
    height: 2rem;
    border-radius: 50%;
    font-size: 0.85rem;
    font-weight: 600;
    margin-bottom: 0.25rem;
}

::deep .step-item.future {
    opacity: 0.5;
}

